A closure is a function that retains access to its lexical scope even when executed outside that scope. <strong>Example:</strong><br/><br/><pre><code>function outer(x) {
  return function inner(y) {
    return x + y;
  };
}
const add5 = outer(5);
console.log(add5(3)); // 8
</code></pre><br/>Here, <code>inner</code> closes over <code>x</code> from <code>outer</code>'s scope. Even after <code>outer</code> has returned, <code>add5</code> retains access to <code>x = 5</code>.

The module pattern uses closures to create private variables and expose only a public API. <strong>Example:</strong><br/><br/><pre><code>const Counter = (function() {
  let count = 0; // private variable
  return {
    increment() { count++; },
    decrement() { count--; },
    getCount() { return count; }
  };
})();
Counter.increment();
console.log(Counter.getCount()); // 1
console.log(Counter.count); // undefined
</code></pre><br/>The <code>count</code> variable is only accessible via the returned methods because those methods form closures over the IIFE's scope.

When using <code>var</code> inside a loop, all callbacks share the same variable binding, so they all see the final value. <strong>Problem:</strong><br/><br/><pre><code>for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
} // logs 3, 3, 3
</code></pre><br/><strong>Fix 1 -- Use <code>let</code> (block scoping):</strong><br/><br/><pre><code>for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
} // logs 0, 1, 2
</code></pre><br/><strong>Fix 2 -- IIFE wrapper:</strong><br/><br/><pre><code>for (var i = 0; i < 3; i++) {
  ((j) => setTimeout(() => console.log(j), 100))(i);
} // logs 0, 1, 2
</code></pre>

Yes, closures can cause memory leaks when they unintentionally retain references to large objects that should be garbage collected. If a closure maintains a reference to a large data structure or DOM element, that data cannot be freed until the closure itself is released. <strong>Example of a leak:</strong><br/><br/><pre><code>function setupHandler() {
  const largeData = new Array(1000000).fill('x');
  document.getElementById('btn').onclick = function() {
    console.log('clicked'); // closure over largeData
  };
}
</code></pre><br/>The click handler's closure keeps <code>largeData</code> alive as long as the DOM element exists. <strong>Fix:</strong> Nullify the reference when no longer needed: <code>largeData = null</code>.

A function factory is a function that returns a new function with specific behavior configured by the factory's arguments. Closures make this possible because the returned function retains access to the factory's arguments. <strong>Example:</strong><br/><br/><pre><code>function multiply(factor) {
  return function(number) {
    return number * factor;
  };
}
const double = multiply(2);
const triple = multiply(3);
console.log(double(5)); // 10
console.log(triple(5)); // 15
</code></pre><br/><code>factor</code> is captured by each returned function via closure.

Closures are essential for preserving state in asynchronous code. A callback passed to <code>.then()</code> or defined inside an <code>async</code> function captures variables from its surrounding scope. <strong>Example:</strong><br/><br/><pre><code>function fetchUser(id) {
  const baseUrl = 'https://api.example.com';
  return fetch(`${baseUrl}/users/${id}`)
    .then(res => res.json())
    .then(data => {
      console.log(`User ${id}:`, data); // `id` is captured via closure
    });
}
</code></pre><br/>The <code>id</code> parameter and <code>baseUrl</code> are available inside the promise chain because each <code>.then</code> callback forms a closure over the <code>fetchUser</code> scope.

Closures capture the <strong>lexical scope</strong> (variables), not the <strong>this</strong> binding. The value of <code>this</code> inside a closure depends on how the function is called, not where it is defined. This is a common source of bugs: <br/><br/><pre><code>const obj = {
  name: 'MyObj',
  logName: function() {
    return function() {
      console.log(this.name); // undefined (or global name)
    };
  }
};
obj.logName()();
</code></pre><br/><strong>Fix:</strong> Use an arrow function (which captures <code>this</code> lexically), or capture <code>this</code> in a variable: <code>const self = this</code>.

codeExamples.code:
function createBankAccount(initialBalance) {
  let balance = initialBalance; // private

  return {
    deposit(amount) {
      if (amount > 0) balance += amount;
      return balance;
    },
    withdraw(amount) {
      if (amount > 0 && amount <= balance) {
        balance -= amount;
        return amount;
      }
      return 0;
    },
    getBalance() { return balance; }
  };
}

const account = createBankAccount(1000);
account.deposit(500);
console.log(account.getBalance()); // 1500
console.log(account.balance);      // undefined (private!)

function createMultiplier(factor) {
  return (value) => value * factor;
}

const double = createMultiplier(2);
const triple = createMultiplier(3);
const tax = createMultiplier(1.08);

console.log(double(10));      // 20
console.log(triple(10));      // 30
console.log(tax(100));        // 108

function fetchWithRetry(url, maxRetries) {
  let attempt = 0;

  function tryFetch() {
    attempt++;
    return fetch(url)
      .then(res => {
        if (!res.ok && attempt < maxRetries) {
          console.log(`Retry ${attempt}/${maxRetries}`);
          return tryFetch(); // recursive call, keeps closure
        }
        return res;
      })
      .catch(() => {
        if (attempt < maxRetries) return tryFetch();
        throw new Error(`Failed after ${maxRetries} attempts`);
      });
  }

  return tryFetch();
}

fetchWithRetry('https://api.example.com/data', 3)
  .then(data => console.log('Success:', data))
  .catch(err => console.error(err));

function curry(fn) {
  return function curried(...args) {
    if (args.length >= fn.length) {
      return fn.apply(this, args);
    } else {
      return function(...nextArgs) {
        return curried.apply(this, args.concat(nextArgs));
      };
    }
  };
}

const sum = (a, b, c) => a + b + c;
const curriedSum = curry(sum);

console.log(curriedSum(1)(2)(3));       // 6
console.log(curriedSum(1, 2)(3));       // 6
console.log(curriedSum(1, 2, 3));       // 6

function memoize(fn) {
  const cache = new Map(); // private cache via closure

  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) {
      console.log('Cache hit:', key);
      return cache.get(key);
    }
    console.log('Cache miss:', key);
    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

const fibonacci = memoize(function fib(n) {
  if (n < 2) return n;
  return fib(n - 1) + fib(n - 2);
});

console.log(fibonacci(40)); // Computed fast via memoization
